  text: string;
  grades?: { grade: string; source: string }[];
  reference?: { book: number; hadith: number };
}

interface SavedHadith {
  id: string; // composite key: bookId-hadithNumber
  bookId: string;
  bookName: string;
  en: Hadith; // This stores the translation (EN or FR) depending on what was saved
  ar?: Hadith;
  timestamp: number;
  lang?: Language; // Track which language was saved
