const TRANSLATIONS = {
  en: {
    collections: "Hadith Collections",
    subtitle: "Authentic narrations from the Sunnah",
    searchChapters: "Search chapters in",
    searchHadith: "Search text...",
    searchSaved: "Search saved...",
    noChapters: "No chapters found.",
    noHadiths: "No hadiths found.",
    noSaved: "No saved hadiths yet.",
    savedTitle: "Saved Hadiths",
    retry: "Retry",
    selectChapter: "Select Chapter",
    saved: "Saved",
    reference: "Reference",
    hadith: "Hadith",
    copy: "Copy to Clipboard",
    removeBookmark: "Remove Bookmark",
    saveBookmark: "Save Bookmark",
    grades: "Grades",
    errorSections: "Could not fetch sections for this book. Please try again later.",
    errorHadiths: "Failed to load hadiths."
  },
  fr: {
    collections: "Collections de Hadiths",
    subtitle: "Narrations authentiques de la Sunnah",
    searchChapters: "Rechercher des chapitres dans",
    searchHadith: "Rechercher dans le texte...",
    searchSaved: "Rechercher...",
    noChapters: "Aucun chapitre trouvé.",
    noHadiths: "Aucun hadith trouvé.",
    noSaved: "Aucun hadith enregistré.",
