import { GoogleGenAI, Type } from "@google/genai";
import { DailyVerse, PlaceResult, DailyHadith } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateDailyVerse = async (language: string = 'en'): Promise<DailyVerse | null> => {
  if (!apiKey) return null;

  const langPrompt = language === 'fr' ? 'French' : 'English';

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a beautiful, inspiring Quranic verse or authentic Hadith for today. Include the Arabic text, ${langPrompt} translation, reference, and a short 1-sentence spiritual reflection in ${langPrompt}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            arabic: { type: Type.STRING },
            translation: { type: Type.STRING },
            reference: { type: Type.STRING },
            reflection: { type: Type.STRING },
          },
          required: ["arabic", "translation", "reference", "reflection"],
        },
      },
    });

    const text = response.text;
    if (text) {
      return JSON.parse(text) as DailyVerse;
    }
  } catch (error) {
    console.error("Error generating verse:", error);
  }
  return null;
};

