export const findMosques = async (lat: number, lng: number, language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "API Key missing", places: [] };

  const langPrompt = language === 'fr' ? 'in French' : 'in English';

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Find the 5 best rated mosques or islamic centers nearby. Provide a brief summary of them ${langPrompt}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lng
            }
          }
        }
      },
    });

    const text = response.text || (language === 'fr' ? "Aucune mosquée trouvée." : "No mosques found.");
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Extract map data
    const places: PlaceResult[] = [];
    chunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title) {
         // Fallback for web chunks if map chunks aren't distinct
         places.push({
             title: chunk.web.title,
             uri: chunk.web.uri
         });
      }
    });

    // Better extraction based on Gemini documentation for Maps
    const mapPlaces = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title,
        uri: c.maps.uri,
        snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet
      }));

    return { text, places: mapPlaces.length > 0 ? mapPlaces : places };

  } catch (error) {
    console.error("Error finding mosques:", error);
    const errorText = language === 'fr' 
      ? "Désolé, impossible de rechercher des mosquées pour le moment." 
      : "Sorry, I couldn't search for mosques at this time.";
    return { text: errorText, places: [] };
  }
};

export const chatWithAi = async (message: string, history: { role: string, parts: { text: string }[] }[], language: string = 'en'): Promise<string> => {
  if (!apiKey) return "API Key missing.";

  const langInstruction = language === 'fr' ? 'You must reply in French.' : 'You must reply in English.';

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      history: history,
      config: {
        systemInstruction: `You are Noor, a knowledgeable, polite, and empathetic Islamic AI companion. You help users with questions about Islam, Duas, history, and spiritual advice. You avoid giving fatwas on controversial legal matters, instead suggesting they consult a local scholar for specific rulings. Keep answers concise, warm, and spiritually uplifting. ${langInstruction}`
      }
    });

    const result = await chat.sendMessage({ message });
    return result.text || (language === 'fr' ? "Je m'excuse, je n'ai pas pu générer de réponse." : "I apologize, I couldn't generate a response.");
  } catch (error) {
    console.error("Chat error:", error);
    return language === 'fr' ? "Désolé, une erreur s'est produite." : "Sorry, something went wrong. Please try again later.";
  }
}

