import React, { useEffect, useState } from 'react';
import { PrayerTimes } from '../types';
import { Clock, Sun, Sunset, Moon, Sunrise } from 'lucide-react';

interface PrayerCardProps {
  timings: PrayerTimes | null;
  loading: boolean;
  language?: string;
}

const TRANSLATIONS = {
  en: { nextPrayer: "Next Prayer" },
  fr: { nextPrayer: "Prochaine Prière" }
};

const PrayerCard: React.FC<PrayerCardProps> = ({ timings, loading, language = 'en' }) => {
  const [nextPrayer, setNextPrayer] = useState<string>('');
  const [timeRemaining, setTimeRemaining] = useState<string>('');

  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  useEffect(() => {
    if (!timings) return;

    const prayers = ['Fajr', 'Dhuhr', 'Asr', 'Maghrib', 'Isha'];

    const updateNextPrayer = () => {
      const now = new Date();
      let upcoming = null;
      let upcomingName = '';

      for (const p of prayers) {
        const [hours, minutes] = timings[p].split(':').map(Number);
        const pTime = new Date();
        pTime.setHours(hours, minutes, 0, 0);

        if (pTime > now) {
          upcoming = pTime;
          upcomingName = p;
          break;
        }
      }

      if (!upcoming) {
        // Next is Fajr tomorrow
        const [hours, minutes] = timings['Fajr'].split(':').map(Number);
        upcoming = new Date();
        upcoming.setDate(upcoming.getDate() + 1);
        upcoming.setHours(hours, minutes, 0, 0);
        upcomingName = 'Fajr';
      }

      setNextPrayer(upcomingName);

      const diff = upcoming.getTime() - now.getTime();
      const diffHrs = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const diffMins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));

      setTimeRemaining(`- ${diffHrs}h ${diffMins}m`);
    };

    updateNextPrayer();
    const interval = setInterval(updateNextPrayer, 60000);
    return () => clearInterval(interval);
  }, [timings]);

  if (loading) {
    return (
      <div className="w-full h-64 bg-slate-100 dark:bg-slate-800 animate-pulse rounded-3xl mb-6"></div>
    );
  }

  if (!timings) return null;

  const getIcon = (name: string) => {
    switch (name) {
      case 'Fajr': return <Sunrise className="w-5 h-5" />;
      case 'Dhuhr': return <Sun className="w-5 h-5" />;
      case 'Asr': return <Sun className="w-5 h-5 opacity-70" />;
      case 'Maghrib': return <Sunset className="w-5 h-5" />;
      case 'Isha': return <Moon className="w-5 h-5" />;
      default: return <Clock className="w-5 h-5" />;
    }
  };

  const prayers = [
    { name: 'Fajr', time: timings.Fajr },
    { name: 'Sunrise', time: timings.Sunrise, isPrayer: false },
    { name: 'Dhuhr', time: timings.Dhuhr },
    { name: 'Asr', time: timings.Asr },
    { name: 'Maghrib', time: timings.Maghrib },
    { name: 'Isha', time: timings.Isha },
  ];

  return (
    <div className="w-full bg-gradient-to-br from-emerald-600 to-teal-800 rounded-3xl p-6 text-white shadow-xl shadow-emerald-900/10 relative overflow-hidden mb-6 group">
      {/* Decorative Background Pattern */}
      <div className="absolute inset-0 opacity-10 pointer-events-none">
        <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <pattern id="islamic-pattern" x="0" y="0" width="40" height="40" patternUnits="userSpaceOnUse">
              <path d="M20 0L40 20L20 40L0 20z" fill="none" stroke="currentColor" strokeWidth="1"/>
              <circle cx="20" cy="20" r="5" fill="currentColor" />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#islamic-pattern)" />
        </svg>
      </div>

      {/* Glow Effect */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-20 -mt-20 blur-3xl group-hover:opacity-10 transition-opacity duration-700"></div>

      <div className="relative z-10 text-center mb-8 mt-2">
        <div className="inline-flex flex-col items-center">
          <p className="text-emerald-100 text-xs font-bold tracking-widest uppercase mb-1 bg-emerald-700/30 px-3 py-1 rounded-full backdrop-blur-sm border border-emerald-500/20">{t.nextPrayer}</p>
          <h2 className="text-5xl font-bold mt-2 mb-1 drop-shadow-sm tracking-tight">{nextPrayer}</h2>
          <p className="text-emerald-50 text-lg font-medium tracking-wide opacity-90">{timeRemaining}</p>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3 relative z-10">
        {prayers.map((p) => {
          const isNext = p.name === nextPrayer;
          if (!p.isPrayer && p.name === 'Sunrise') return null; 

          return (
            <div key={p.name} className={`flex flex-col items-center justify-center p-3 rounded-2xl transition-all duration-300 ${isNext ? 'bg-white/20 backdrop-blur-md border border-white/30 shadow-lg scale-105' : 'bg-black/10 border border-white/5 hover:bg-white/10'}`}>
              <div className={`mb-1.5 ${isNext ? 'text-white' : 'text-emerald-100'}`}>
                {getIcon(p.name)}
              </div>
              <span className={`text-[10px] font-bold uppercase tracking-wider ${isNext ? 'text-white' : 'text-emerald-200'}`}>{p.name}</span>
              <span className={`text-sm font-bold mt-0.5 ${isNext ? 'text-white' : 'text-emerald-50'}`}>{p.time.split(' ')[0]}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

