    if (typeof window !== 'undefined') return localStorage.getItem('language') || 'en';
    return 'en';
  });
  const [calculationMethod, setCalculationMethod] = useState(() => {
    if (typeof window !== 'undefined') return parseInt(localStorage.getItem('calc_method') || '2');
    return 2;
  });
  const [prayerOffsets, setPrayerOffsets] = useState<Record<string, number>>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('prayer_offsets');
        return saved ? JSON.parse(saved) : {};
    }
    return {};
  });

  // Dark Mode State
  const [darkMode, setDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('darkMode');
      if (saved === null) {
          return window.matchMedia('(prefers-color-scheme: dark)').matches;
      }
      return saved === 'true';
    }
    return false;
  });

