  // Apply Dark Mode Class
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('darkMode', 'true');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('darkMode', 'false');
    }
  }, [darkMode]);

  // Save Settings
  useEffect(() => {
    localStorage.setItem('calc_method', calculationMethod.toString());
    localStorage.setItem('prayer_offsets', JSON.stringify(prayerOffsets));
    localStorage.setItem('language', language);
  }, [calculationMethod, prayerOffsets, language]);

  // Initial Location Fetch
  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({ lat: position.coords.latitude, lng: position.coords.longitude });
        },
        (error) => {
          console.warn("Location permission denied, defaulting to London", error);
          setLocation({ lat: 51.5074, lng: -0.1278 });
        }
